//import logo from './logo.svg';
import './App.css';
import { Routes,Route,Link } from 'react-router-dom';

function Home(){
  return (
    <div>
      <iframe
        src="/pages/index.html"
        width="100%"
        height="500px"
        title="Register"
    />
    </div>

  );
}
function Signin(){
  return (
    <iframe
      src="/pages/signin.html"
      width="100%"
      height="500px"
      title="Register"
    />
  );
}
function Register(){
  return (
    <iframe
      src="/pages/register.html"
      width="100%"
      height="500px"
      title="Register"
    />
  );
}
function Dashboard(){
  return (
    <iframe
      src="/pages/dashboard.html"
      width="100%"
      height="500px"
      title="Register"
    />
  );
}
function SugarMonitor(){
  return (
    <iframe
      src="/pages/sugarMonitor.html"
      width="100%"
      height="500px"
      title="Register"
    />
  );
}
function EmotionMonitor(){
  return (
    <iframe
      src="/pages/emotionTracking.html"
      width="100%"
      height="500px"
      title="Register"
    />
  );
}
function WeeklyReport(){
  return (
    <iframe
      src="/pages/report.html"
      width="100%"
      height="500px"
      title="Register"
    />
  );
}
function FoodTracking(){
  return (
    <iframe
      src="/pages/foodTracking.html"
      width="100%"
      height="500px"
      title="Register"
    />
  );
}
function NavBar(){
  return(
    <div className="navSection">
      <ul>
        <li><Link to="/">Home</Link></li>
        <li><Link to="/signin">Signin</Link></li>
        <li><Link to="/register">Register</Link></li>
        <li><Link to="/dashboard"></Link></li>
        <li><Link to="/sugarMonitor"></Link></li>
        <li><Link to="/emotionMonitor"></Link></li>
        <li><Link to="/report"></Link></li>
        <li><Link to="/foodMonitor"></Link></li>
      </ul>
    </div>
  );
}
function App() {
  /*return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <p>
          Edit <code>src/App.js</code> and save to reload.
        </p>
        <a
          className="App-link"
          href="https://reactjs.org"
          target="_blank"
          rel="noopener noreferrer"
        >
          Learn React
        </a>
      </header>
    </div>
  );*/
  return (
    <div>
      <NavBar />
      <Routes>
        <Route path='/' element={<Home />} />
        <Route path='/signin' element={<Signin />} />
        <Route path='/register' element={<Register />} />
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/sugarMonitor" element={<SugarMonitor />} />
        <Route path="/emotionMonitor" element={<EmotionMonitor />} />
        <Route path="/report" element={<WeeklyReport />} />
        <Route path="/foodMonitor" element={<FoodTracking />} />
      </Routes>
    </div>
  );
}


export default App;
